package com.google.gson;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import java.lang.reflect.Field;

public class GsonBuilderTest {

  @Test
  void testEnableComplexMapKeySerialization() throws Exception {
    GsonBuilder gsonBuilder = new GsonBuilder();

    // Initially complexMapKeySerialization should be false (default)
    Field field = GsonBuilder.class.getDeclaredField("complexMapKeySerialization");
    field.setAccessible(true);
    boolean before = field.getBoolean(gsonBuilder);
    assertFalse(before, "complexMapKeySerialization should be false by default");

    // Call enableComplexMapKeySerialization()
    GsonBuilder returned = gsonBuilder.enableComplexMapKeySerialization();

    // The returned instance should be the same
    assertSame(gsonBuilder, returned, "enableComplexMapKeySerialization should return this");

    // complexMapKeySerialization should now be true
    boolean after = field.getBoolean(gsonBuilder);
    assertTrue(after, "complexMapKeySerialization should be true after enabling");
  }
}
